function setJsonGeo(content: string, geo: GeoLocation | null): string {
  const parsed = JSON.parse(content) as Record<string, unknown>;
  if (geo) {
    const [lng, lat] = geo.coordinates;
    parsed._geo = { lat, lng, ...(geo.label ? { label: geo.label } : {}) };
  } else {
