// Client-safe constants shared between server (workspace.ts) and client UI.
// Anything here must be pure values — no "server-only" imports.

// Caps how long a stratbook name can be. Sized so the OG cover image
// (renderCoverImage wraps at 34 chars/line × 2 lines) and the app-shell
// project header don't truncate awkwardly.
export const MAX_PROJECT_NAME_LENGTH = 60;
export type WorkspaceSource = "supabase";

export interface Project {
  id: string;
  name: string;
  description?: string;
  createdAt: string;
  coverImage?: ProjectCoverImage;
  exampleVersion?: string;
  onboardingComplete: boolean;
  updatedAt?: string;
  sharing?: ProjectSharing;
  forkedFrom?: ProjectForkSource;
}

export interface ProjectCoverImage {
  height: number;
  markerHash: string;
  storagePath: string;
  updatedAt: string;
  width: number;
}

export interface ProjectSharing {
  isPublic: boolean;

export async function readSharedWorkspaceFile(
  shareId: string,
  workspacePath: string
): Promise<WorkspaceFile> {
  const { manifest } = await getSharedProject(shareId);
  return readWorkspaceFile(manifest.ownerId, manifest.projectId, workspacePath);
}

export async function readSharedProjectCoverImage(shareId: string): Promise<Blob> {
  const { manifest } = await getSharedProject(shareId);
  return readProjectCoverImage(manifest.ownerId, manifest.projectId);
}

export async function forkSharedProject(
  shareId: string,
  targetOwnerId: string
): Promise<Project> {
  if (!hasSupabaseStorageConfig()) throw new SupabaseNotConfiguredError();
  validateOwnerId(targetOwnerId);

  const { manifest, project: sourceProject } = await getSharedProject(shareId);
  const now = new Date().toISOString();
  const forkedProject: Project = {
    createdAt: now,
    description: sourceProject.description,
    forkedFrom: {
      forkedAt: now,
      ownerId: manifest.ownerId,
      projectId: manifest.projectId,
      shareId,
    },
    id: nanoid(10),
    name: `${sourceProject.name} (Fork)`,
    onboardingComplete: true,
    updatedAt: now,
  };

  await writeProjectJson(targetOwnerId, forkedProject);

  const rawFiles = await listProjectFiles(manifest.ownerId, manifest.projectId);
